SELECT d.atrz_dmnd_id, d.atrz_task_id, d.rfrnc_tbl_nm, d.rfrnc_key_cn, d.dmnd_user_id, d.dmnd_dt, d.atrz_st_cd, d.title, d.contents, d.use_bgng_dt, d.use_end_dt, d.frst_reg_dt, d.frst_reg_user_id, d.last_chg_dt, d.last_chg_user_id FROM com.tn_atrz_dmnd d JOIN com.tn_atrz_task t ON t.atrz_task_id = d.atrz_task_id AND NOW() BETWEEN t.use_bgng_dt AND t.use_end_dt WHERE NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt
AND d.atrz_task_id = #{atrzTaskId}
AND d.atrz_st_cd = #{atrzStCd}
AND d.dmnd_user_id = #{dmndUserId}
AND d.dmnd_dt >= CAST(#{dateFrom} AS DATE)
AND d.dmnd_dt < CAST(#{dateTo} AS DATE) + INTERVAL '1 day'
ORDER BY d.dmnd_dt DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(d.atrz_dmnd_id)
  FROM com.tn_atrz_dmnd d
  JOIN com.tn_atrz_task t ON t.atrz_task_id = d.atrz_task_id
                          AND NOW() BETWEEN t.use_bgng_dt AND t.use_end_dt
 WHERE NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt

   AND d.atrz_task_id = #{atrzTaskId}


   AND d.atrz_st_cd = #{atrzStCd}


   AND d.dmnd_user_id = #{dmndUserId}


   AND d.dmnd_dt >= CAST(#{dateFrom} AS DATE)


   AND d.dmnd_dt < CAST(#{dateTo} AS DATE) + INTERVAL '1 day'

mapper.update:
UPDATE com.tn_atrz_dmnd
   SET atrz_st_cd       = #{atrzStCd},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE atrz_dmnd_id = #{atrzDmndId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
